const s="/assets/Landing3-BRSMsbAk.png",o="/assets/Landing2--RXZxlhA.png",e="/assets/Landing1-CWRst0mZ.png",r="/assets/supervisor1-B3xw5Jck.png",l="/assets/supervisor2-C1Wc5PMp.png",a="/assets/supervisor3-D7ApSbEj.png",t="/assets/OverViewImage-BVWCXmKe.png",c="/assets/LoginImage-OAAqqXQj.png",p="/assets/ComponentManagmentImage-DmgNkSMe.png",g="/assets/ComponentManagmentImage2-BeaUyJdW.png",d="/assets/ImportSwagger1-CT2GrjqO.png",m="/assets/ImportSwagger2-CXrdfdp2.png",u="/assets/ImportSwagger3-D7EDpyPd.png",h="/assets/ImportSwagger4-DBARtUsL.png",v="/assets/CreatePage1-DQkXdoqF.png",f="/assets/CreatePage2-DT4Sx-MH.png",w="/assets/CreatePage3-BHlv9k2o.png",b="/assets/UserOverView1-DeDhOpi-.png",i="/assets/AdminDashboard-C3uqE3h6.png",y="/assets/createBuffer-DOfNtuT5.png",P="/assets/walletPic-DXtoG9kx.png",S="/assets/parcelDetail-y149qN9R.png",A="/assets/createNode-B9Sxz-Zs.png",z="/assets/mapPicpng-BwUv9jth.png",n="/assets/baseMapPic-CiABCbh6.png",D="/assets/managment-fleet-Cu2wyHN4.png",C="/assets/managment-bundleList-DaRwMUXv.png",k="/assets/createOrder-XFSaRnWU.png",I=[{id:1,slug:"Halazone-Management",title:"Halazone-Management",img:i,description:"A reusable UI component library with comprehensive documentation.",technologies:["React","TypeScript","TailwindCSS","Storybook"],repo:"https://github.com/"},{id:2,slug:"HalazMap",title:"Halazone-Map",img:n,description:"An interactive map-based dashboard for monitoring nodes, zones, operational activities, and real-time fleet locations.",technologies:["React","TypeScript","Zustand","TailwindCSS"],repo:"https://github.com/"},{id:3,slug:"customerPanel",title:"Halazone-CustomerPanel",img:k,description:"A user-friendly interface where customers can select services, place orders, and track their status in real time.",technologies:["React","TypeScript","ContextApi","Zustand","TailwindCSS"],repo:"https://github.com/"},{id:4,slug:"Halazone-SupervisorApp",title:"Halazone-SupervisorApp",img:a,description:"A monitoring dashboard enabling supervisors to track parcels, fleet activity, and operational status in real time.",technologies:["React","TypeScript","Zustand","leaflet","TailwindCSS"],repo:"https://github.com/"},{id:5,slug:"Halazone-LandingPage",title:"Halazone-LandingPage",img:e,description:"Designed to communicate the platform’s vision, solutions, and user benefits through a clean, engaging UI.",technologies:["Next.js","TypeScript","Zustand","TailwindCSS"],repo:"https://github.com/"},{id:6,slug:"Dynamic_ApiDocBuilder",title:"Dynamic_ApiDocBuilder",img:t,description:"A dynamic API documentation platform that automatically generates and manages interactive API docs for developers",technologies:["Next.js","TypeScripts","TailwindCSS","React Context API"]}],T={1:{title:"Halazone – Management System",paragraphs:["A centralized admin platform providing full system access and control over operational workflows, configurations, and data management."],detailContent:["The Halazone Management System is a comprehensive admin dashboard built to give operators full visibility and control over the entire logistics platform.","It covers fleet management, bundle tracking, user administration, and operational reporting — all in one unified interface.","Built with performance and scalability in mind, the system handles large volumes of real-time data while keeping the UI responsive and intuitive for admin users."],images:[D,i,C]},2:{title:" Halazone - Map",paragraphs:["A map-driven interface enabling dynamic rendering of zones, nodes, operational layers, and live vehicle tracking. Built with a focus on performance, responsiveness, and data clarity."],detailContent:["Halazone Map is an interactive geospatial dashboard for visualizing and managing logistics operations in real time.","Operators can view and edit delivery zones, monitor node status, and track live vehicle positions on the map — all with smooth pan and zoom interactions.","The system layers multiple data sources simultaneously, giving a clear operational picture without overwhelming the interface."],images:[A,z,n]},3:{title:"Halazone – Customer Panel",paragraphs:["The customer panel provides users with a seamless experience for creating and managing orders.","Users can select destinations, services, and track their shipments in real time."],detailContent:["The Halazone Customer Panel is the end-user facing application where customers interact with the platform to create orders, manage their wallet, and track deliveries.","The interface guides users through service selection, destination input, and order confirmation — with a clean step-by-step flow designed to minimize friction.","Real-time shipment tracking and parcel detail views keep customers informed at every stage of their delivery."],images:[y,P,S]},4:{title:"Halazone – Supervisor App",paragraphs:["The supervisor application is a PWA designed for monitoring microhub operations.","It enables supervisors to manage fleets and shipments in real time."],detailContent:["The Halazone Supervisor App is a Progressive Web App designed for field supervisors managing microhub logistics on the go.","Supervisors can monitor parcel intake and dispatch, track fleet activity, and resolve operational issues directly from their mobile device.","Built as a PWA, it works reliably across devices and network conditions — critical for field operations where connectivity can be inconsistent."],images:[r,l,a]},5:{title:"Halazone – Landing Page",paragraphs:["The landing page introduces Halazone’s services and features.","It is optimized for performance, SEO, and user engagement."],detailContent:["The Halazone Landing Page is the public-facing marketing site that introduces the platform’s logistics services and value proposition.","Designed to convert visitors into users, it communicates the platform’s key features through clean visuals, structured sections, and clear calls to action.","Built with Next.js for optimal SEO performance and fast initial load, ensuring strong search visibility and a smooth first impression."],link:{label:"View Live Project",url:"https://halazoneco.com/"},images:[s,o,e]},6:{title:"Dynamic_ApiDocBuilder",paragraphs:["Dynamic DocsPlatform is a dynamic platform for creating, managing, and publishing API documentation.","It helps developers build interactive and organized API docs with a simple and flexible workflow."],detailContent:["Dynamic ApiDocBuilder is a full-featured platform for creating, organizing, and publishing interactive API documentation — built entirely on the frontend with Next.js.","Developers can import Swagger/OpenAPI specs directly, with the platform automatically parsing and rendering endpoints into structured, navigable pages.","Beyond auto-import, the platform supports manual component management, custom page creation, and role-based access — making it flexible for both small APIs and large multi-team projects."],link:{label:"View Project Source",url:"https://github.com/MobinaLalani/DynamicFrontEndDocsProject-Next.git"},images:[t,c,p,g,d,m,u,h,v,f,w,b]}};export{T as a,I as p};
